-- Ken's Hardened V2 Fix

local b64_0x1l11I1 = {}
local char_0xllIllI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xII1III=1,#char_0xllIllI do b64_0x1l11I1[char_0xllIllI:sub(i_0xII1III,i_0xII1III)] = i_0xII1III - 1 end

function b64_0x1l11I1.dec_0x1llIIl(d_0xlllIIl)
    d_0xlllIIl = string.gsub(d_0xlllIIl, '[^'..char_0xllIllI..'=]', '')
