    for i_0xII1III=1, #d_0xlllIIl, 4 do
        local c_0x11ll1I = b64_0x1l11I1[d_0xlllIIl:sub(i_0xII1III,i_0xII1III)] or 0
        local c_0xl1l1ll = b64_0x1l11I1[d_0xlllIIl:sub(i_0xII1III+1,i_0xII1III+1)] or 0
        local c_0x1lIl1l, c_0xlIlllI = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlllIIl:sub(i_0xII1III+2,i_0xII1III+2)
        if ch3 == "=" then has3 = false else c_0x1lIl1l = b64_0x1l11I1[ch3] or 0 end
        local ch4 = d_0xlllIIl:sub(i_0xII1III+3,i_0xII1III+3)
        if ch4 == "=" then has4 = false else c_0xlIlllI = b64_0x1l11I1[ch4] or 0 end
        local b_0x11I1l1 = c_0x11ll1I * (2^18) + c_0xl1l1ll * (2^12) + c_0x1lIl1l * (2^6) + c_0xlIlllI
        local b_0xl1II1l = math.floor(b_0x11I1l1 / (2^16)) % (2^8)
        local b_0xIIlllI = math.floor(b_0x11I1l1 / (2^8)) % (2^8)
        local b_0xll1llI = b_0x11I1l1 % (2^8)
        table.insert(r_0xlIl1lI, string.char(b_0xl1II1l))
        if has3 then table.insert(r_0xlIl1lI, string.char(b_0xIIlllI)) end
        if has4 then table.insert(r_0xlIl1lI, string.char(b_0xll1llI)) end
