end


local function bxor_0xI1lIII(a_0xIIl1l1,b_0xIIIIll)
    if bit32 then return bit32.bxor(a_0xIIl1l1,b_0xIIIIll) end
    local r_0x1llll1 = 0
    for i_0xIIlI11 = 0, 7 do
        local x_0xllIIII = a_0xIIl1l1 % 2
        local y_0xIIl1ll = b_0xIIIIll % 2
        if x_0xllIIII ~= y_0xIIl1ll then r_0x1llll1 = r_0x1llll1 + (2^i_0xIIlI11) end
        a_0xIIl1l1 = math.floor(a_0xIIl1l1 / 2)
        b_0xIIIIll = math.floor(b_0xIIIIll / 2)
    end
    return r_0x1llll1
end


local function bxor_str_0xlllIII(s_0xI1I1Il, k_0xl11lII)
    local r_0xIll1I1 = {}
    for i_0xlI1Ill=1, #s_0xI1I1Il do
        local b_0xlIIlII = string.byte(s_0xI1I1Il, i_0xlI1Ill)
        local kb_0xllI1II = string.byte(k_0xl11lII, (i_0xlI1Ill-1) % #k_0xl11lII + 1)
        r_0xIll1I1[i_0xlI1Ill] = string.char(bxor_0xI1lIII(b_0xlIIlII, kb_0xllI1II))
    end
    return table.concat(r_0xIll1I1)
end


local function getkeys_0xl1lI1I()
    local seed = b64_0x1l11I1.dec_0x1llIIl("cEZ4UHNBZ2I=")
    local k1_enc = b64_0x1l11I1.dec_0x1llIIl("JxwPYx4GJjI=")
    local k2_enc = b64_0x1l11I1.dec_0x1llIIl("CnAuZCYWEVo=")
    return bxor_str_0xlllIII(k1_enc, seed), bxor_str_0xlllIII(k2_enc, seed)
end


local function cff_0xII1IIl(a_0xlllllI)
    local st_0xI1Ill1 = 0
    local res_0xIIIIlI = a_0xlllllI
    while true do
        if st_0xI1Ill1 == 0 then
            res_0xIIIIlI = res_0xIIIIlI + 1
            st_0xI1Ill1 = 1
        elseif st_0xI1Ill1 == 1 then
            res_0xIIIIlI = res_0xIIIIlI * 2
            st_0xI1Ill1 = 2
        elseif st_0xI1Ill1 == 2 then
            res_0xIIIIlI = res_0xIIIIlI - 3
            st_0xI1Ill1 = 3
        else
            break
        end
    end
    return res_0xIIIIlI
end


local function chain_0xlIIIlI(x) return x*2 end
local function chain_0xIlIIll(x) return chain_0xlIIIlI(x)+1 end


local d_0xlll11I = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIlIII = 1
local stk_0x1IlIll = {}
stk_0x1IlIll._jmp = nil


local disp_0x111l1l = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xl1lI1I()

local state_0xlIII1I = 0
while true do
    if state_0xlIII1I == 0 then  -- FETCH
        if pc_0xlIlIII > #d_0xlll11I then break end
        local inst = d_0xlll11I[pc_0xlIlIII]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
